import React, { useState } from 'react';

const campos = [
  { name: 'CN', label: 'CN' },
  { name: 'DadoInformado', label: 'Dado Informado' },
  { name: 'Servico', label: 'Serviço' },
  { name: 'UF', label: 'UF' },
  { name: 'Valores', label: 'Valores' },
  { name: 'CNPJ', label: 'CNPJ' },
  { name: 'DATA', label: 'DATA' },
];

const opcoesDadoInformado = [
  'Receita_Operacional_Líqu',
  'Capital_Expenditure_CAPI',
  'Tráfego_Dados_Total_MB',
];

const opcoesServico = ['SCM'];
const opcoesUF = [
  'AC','AL','AP','AM','BA','CE','DF','ES','GO','MA','MT','MS','MG','PA','PB','PR','PE','PI','RJ','RN','RS','RO','RR','SC','SP','SE','TO'
];

export default function TabelaRelatorioEconomico({ cnpjPadrao, dataPadrao }) {
  const [linhas, setLinhas] = useState([
    { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjPadrao || '', DATA: dataPadrao || '' },
    { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjPadrao || '', DATA: dataPadrao || '' },
    { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjPadrao || '', DATA: dataPadrao || '' },
    { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjPadrao || '', DATA: dataPadrao || '' },
    { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjPadrao || '', DATA: dataPadrao || '' },
    { CN: '0', DadoInformado: '', Servico: 'SCM', UF: '', Valores: '', CNPJ: cnpjPadrao || '', DATA: dataPadrao || '' },
  ]);

  const handleChange = (idx, campo, valor) => {
    setLinhas(linhas => linhas.map((linha, i) => i === idx ? { ...linha, [campo]: valor } : linha));
  };

  const handleCSV = () => {
    const header = campos.map(c => c.label).join(';');
    const rows = linhas.map(linha => campos.map(c => linha[c.name]).join(';'));
    const csv = [header, ...rows].join('\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.setAttribute('download', 'relatorio_economico.csv');
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div style={{background:'#fff',padding:24,borderRadius:12,boxShadow:'0 2px 8px #0001',maxWidth:1200,margin:'2rem auto'}}>
      <h2>Formulário</h2>
      <table style={{width:'100%',marginBottom:16}}>
        <thead>
          <tr>
            {campos.map(c => <th key={c.name}>{c.label}</th>)}
          </tr>
        </thead>
        <tbody>
          {linhas.map((linha, idx) => (
            <tr key={idx}>
              <td><input value={linha.CN} onChange={e => handleChange(idx, 'CN', e.target.value)} style={{width:50}} /></td>
              <td>
                <select value={linha.DadoInformado} onChange={e => handleChange(idx, 'DadoInformado', e.target.value)}>
                  <option value="">Selecione</option>
                  {opcoesDadoInformado.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                </select>
              </td>
              <td>
                <select value={linha.Servico} onChange={e => handleChange(idx, 'Servico', e.target.value)}>
                  {opcoesServico.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                </select>
              </td>
              <td>
                <select value={linha.UF} onChange={e => handleChange(idx, 'UF', e.target.value)}>
                  <option value="">Selecione</option>
                  {opcoesUF.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                </select>
              </td>
              <td><input value={linha.Valores} onChange={e => handleChange(idx, 'Valores', e.target.value)} /></td>
              <td><input value={linha.CNPJ} onChange={e => handleChange(idx, 'CNPJ', e.target.value)} /></td>
              <td><input value={linha.DATA} onChange={e => handleChange(idx, 'DATA', e.target.value)} /></td>
            </tr>
          ))}
        </tbody>
      </table>
      <button onClick={handleCSV} style={{background:'#d32f2f',color:'#fff',border:'none',borderRadius:4,padding:'0.7rem 2rem',fontWeight:'bold',fontSize:16,cursor:'pointer'}}>Gerar CSV</button>
    </div>
  );
}
